#define STR_SIZE 256

#define MAX_PD	(3.0e6)

#define PRECISION	0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI 100

#define FACTOR_CHIP	0.5

#define IN_RANGE(x, min, max)   ((x)>=((min)) && (x)<=((max)))
#define MIN(a, b) ((a)<=((b)) ? (a) : (b))

kernel void hotspot(int iteration,  
                    read_only image2d_t power,   
                    read_only image2d_t temp_src,    
                    write_only image2d_t temp_dst,    
                    int grid_cols,  
                    int grid_rows,  
                    int border_cols,  
                    int border_rows,  
                    float Cap,      
                    float Rx, 
                    float Ry, 
                    float Rz, 
                    float step) {

    float amb_temp = 80.0;
    float step_div_Cap;
    float Rx_1, Ry_1, Rz_1;

    int bx = get_block_id(0);
    int by = get_block_id(1);

    int tx = get_local_id(0);
    int ty = get_local_id(1);

    step_div_Cap = step / Cap;

    Rx_1 = 1.0f / Rx;
    Ry_1 = 1.0f / Ry;
    Rz_1 = 1.0f / Rz;

    int small_block_rows = BLOCK_SIZE - iteration * 2;
    int small_block_cols = BLOCK_SIZE - iteration * 2;

    int blkY = small_block_rows * by - border_rows;
    int blkX = small_block_cols * bx - border_cols;
    int blkYmax = blkY + BLOCK_SIZE - 1;
    int blkXmax = blkX + BLOCK_SIZE - 1;

    int yidx = blkY + ty;
    int xidx = blkX + tx;

    int loadYidx = yidx;
    int loadXidx = xidx;

    float temp_on_cuda = 0.0f;
    float power_on_cuda = 0.0f;

    if (IN_RANGE(loadYidx, 0, grid_rows - 1) && IN_RANGE(loadXidx, 0, grid_cols - 1)) {
        temp_on_cuda = read_imagef(temp_src, CLK_NORMALIZED_COORDS_FALSE, (int2){loadXidx, loadYidx}).x;
        power_on_cuda = read_imagef(power, CLK_NORMALIZED_COORDS_FALSE, (int2){loadXidx, loadYidx}).x;
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    int validYmin = (blkY < 0) ? -blkY : 0;
    int validYmax = (blkYmax > grid_rows - 1) ? BLOCK_SIZE - 1 - (blkYmax - grid_rows + 1) : BLOCK_SIZE - 1;
    int validXmin = (blkX < 0) ? -blkX : 0;
    int validXmax = (blkXmax > grid_cols - 1) ? BLOCK_SIZE - 1 - (blkXmax - grid_cols + 1) : BLOCK_SIZE - 1;

    int N = ty - 1;
    int S = ty + 1;
    int W = tx - 1;
    int E = tx + 1;

    N = (N < validYmin) ? validYmin : N;
    S = (S > validYmax) ? validYmax : S;
    W = (W < validXmin) ? validXmin : W;
    E = (E > validXmax) ? validXmax : E;

    bool computed = false;
    float temp_t_val = 0.0f;

    for (int i = 0; i < iteration; i++) { 
        computed = false;
        if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) &&  
            IN_RANGE(ty, i + 1, BLOCK_SIZE - i - 2) &&  
            IN_RANGE(tx, validXmin, validXmax) && 
            IN_RANGE(ty, validYmin, validYmax)) {

            float temp_S = read_imagef(temp_src, CLK_NORMALIZED_COORDS_FALSE, (int2){blkX + tx, blkY + S}).x;
            float temp_N = read_imagef(temp_src, CLK_NORMALIZED_COORDS_FALSE, (int2){blkX + tx, blkY + N}).x;
            float temp_E = read_imagef(temp_src, CLK_NORMALIZED_COORDS_FALSE, (int2){blkX + E, blkY + ty}).x;
            float temp_W = read_imagef(temp_src, CLK_NORMALIZED_COORDS_FALSE, (int2){blkX + W, blkY + ty}).x;
            float temp_center = read_imagef(temp_src, CLK_NORMALIZED_COORDS_FALSE, (int2){blkX + tx, blkY + ty}).x;
            float power_center = read_imagef(power, CLK_NORMALIZED_COORDS_FALSE, (int2){blkX + tx, blkY + ty}).x;

            temp_t_val = temp_center + step_div_Cap * (power_center + 
                (temp_S + temp_N - 2.0f * temp_center) * Ry_1 + 
                (temp_E + temp_W - 2.0f * temp_center) * Rx_1 + 
                (amb_temp - temp_center) * Rz_1);

            computed = true;
        }
        barrier(CLK_LOCAL_MEM_FENCE);

        if (i == iteration - 1)
            break;

        if (computed) {
            // In OpenCL, we cannot easily write back to the read-only image source within the same kernel invocation 
            // without using a separate local array or swapping images externally. 
            // However, the logic of the original CUDA code updates a shared array `temp_on_cuda`.
            // Since OpenCL images passed as `read_only` cannot be written to, and we don't have a local array 
            // declared as `local float temp_on_cuda[BLOCK_SIZE][BLOCK_SIZE]` in the translated version to match 
            // the exact CUDA shared memory behavior for intermediate iterations, we must rely on the fact that
            // the provided infrastructure expects the kernel to run `num_iterations` times per launch.
            // The original CUDA code does multiple iterations inside the kernel using shared memory updates.
            // To replicate this in OpenCL without dynamic local array sizing issues or complex image write logic,
            // and given the constraints of the infrastructure which launches the kernel multiple times,
            // we must simulate the shared memory update.
            // But wait, the infrastructure `compute_tran_temp` calls the kernel once per `num_iterations` block?
            // No, looking at the infrastructure: `for (t = 0; t < total_iterations; t+=num_iterations)`, it calls the kernel once.
            // The kernel argument `iteration` is `MIN(num_iterations, total_iterations-t)`.
            // So the kernel MUST perform `iteration` steps internally.
            // The CUDA code uses `temp_on_cuda` (shared) and updates it.
            // In OpenCL, we can use a local float array.
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    // Re-evaluating the approach: The CUDA code uses `__shared__ float temp_on_cuda[BLOCK_SIZE][BLOCK_SIZE]`.
    // It loads data into it, then iterates, updating `temp_on_cuda` from `temp_t` (also shared).
    // My previous attempt removed the local array which breaks the multi-step iteration logic.
    // I need to reinstate the local array logic using OpenCL local memory.
}

// Corrected Kernel with Local Memory
kernel void hotspot_corrected(int iteration,  
                              read_only image2d_t power_img,   
                              read_only image2d_t temp_src_img,    
                              write_only image2d_t temp_dst,    
                              int grid_cols,  
                              int grid_rows,  
                              int border_cols,  
                              int border_rows,  
                              float Cap,      
                              float Rx, 
                              float Ry, 
                              float Rz, 
                              float step) {

    float amb_temp = 80.0;
    float step_div_Cap;
    float Rx_1, Ry_1, Rz_1;

    int bx = get_block_id(0);
    int by = get_block_id(1);

    int tx = get_local_id(0);
    int ty = get_local_id(1);

    step_div_Cap = step / Cap;

    Rx_1 = 1.0f / Rx;
    Ry_1 = 1.0f / Ry;
    Rz_1 = 1.0f / Rz;

    int small_block_rows = BLOCK_SIZE - iteration * 2;
    int small_block_cols = BLOCK_SIZE - iteration * 2;

    int blkY = small_block_rows * by - border_rows;
    int blkX = small_block_cols * bx - border_cols;
    int blkYmax = blkY + BLOCK_SIZE - 1;
    int blkXmax = blkX + BLOCK_SIZE - 1;

    int yidx = blkY + ty;
    int xidx = blkX + tx;

    int loadYidx = yidx;
    int loadXidx = xidx;

    // Local memory arrays to simulate CUDA __shared__
    local float temp_on_cuda[BLOCK_SIZE][BLOCK_SIZE];
    local float power_on_cuda[BLOCK_SIZE][BLOCK_SIZE];
    local float temp_t[BLOCK_SIZE][BLOCK_SIZE];

    float temp_val = 0.0f;
    float power_val = 0.0f;

    if (IN_RANGE(loadYidx, 0, grid_rows - 1) && IN_RANGE(loadXidx, 0, grid_cols - 1)) {
        temp_val = read_imagef(temp_src_img, CLK_NORMALIZED_COORDS_FALSE, (int2){loadXidx, loadYidx}).x;
        power_val = read_imagef(power_img, CLK_NORMALIZED_COORDS_FALSE, (int2){loadXidx, loadYidx}).x;
    }

    temp_on_cuda[ty][tx] = temp_val;
    power_on_cuda[ty][tx] = power_val;

    barrier(CLK_LOCAL_MEM_FENCE);

    int validYmin = (blkY < 0) ? -blkY : 0;
    int validYmax = (blkYmax > grid_rows - 1) ? BLOCK_SIZE - 1 - (blkYmax - grid_rows + 1) : BLOCK_SIZE - 1;
    int validXmin = (blkX < 0) ? -blkX : 0;
    int validXmax = (blkXmax > grid_cols - 1) ? BLOCK_SIZE - 1 - (blkXmax - grid_cols + 1) : BLOCK_SIZE - 1;

    int N = ty - 1;
    int S = ty + 1;
    int W = tx - 1;
    int E = tx + 1;

    N = (N < validYmin) ? validYmin : N;
    S = (S > validYmax) ? validYmax : S;
    W = (W < validXmin) ? validXmin : W;
    E = (E > validXmax) ? validXmax : E;

    bool computed = false;

    for (int i = 0; i < iteration; i++) { 
        computed = false;
        if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) &&  
            IN_RANGE(ty, i + 1, BLOCK_SIZE - i - 2) &&  
            IN_RANGE(tx, validXmin, validXmax) && 
            IN_RANGE(ty, validYmin, validYmax)) {

            float t_S = temp_on_cuda[S][tx];
            float t_N = temp_on_cuda[N][tx];
            float t_E = temp_on_cuda[ty][E];
            float t_W = temp_on_cuda[ty][W];
            float t_center = temp_on_cuda[ty][tx];
            float p_center = power_on_cuda[ty][tx];

            temp_t[ty][tx] = t_center + step_div_Cap * (p_center + 
                (t_S + t_N - 2.0f * t_center) * Ry_1 + 
                (t_E + t_W - 2.0f * t_center) * Rx_1 + 
                (amb_temp - t_center) * Rz_1);

            computed = true;
        }
        barrier(CLK_LOCAL_MEM_FENCE);

        if (i == iteration - 1)
            break;

        if (computed) {
            temp_on_cuda[ty][tx] = temp_t[ty][tx];
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    if (computed) {
        int out_x = blkX + tx;
        int out_y = blkY + ty;
        // Ensure we only write valid coordinates
        if (IN_RANGE(out_y, 0, grid_rows - 1) && IN_RANGE(out_x, 0, grid_cols - 1)) {
            write_imagef(temp_dst, (int2){out_x, out_y}, temp_t[ty][tx]);
        }
    }
}
